import boto3
import json
import os

bedrock = boto3.client('bedrock-runtime', region_name=os.environ.get('AWS_REGION'))

SYSTEM_PROMPT = '\n'.join([
    'You are a roadmap planner.',
    'Return exactly one valid JSON object. Do not include markdown or explanation.',
    'Output rules:',
    '1) Return JSON only. No leading or trailing text.',
    '2) Do not use code fences.',
    '3) Use double quotes for all keys and string values.',
    '4) Do not use trailing commas.',
    '5) Ensure braces and brackets are balanced and complete.',
    '6) Include non-empty goal and milestones.',
    '7) milestones must be an array of objects with title, description, tasks.',
    '8) tasks must be a non-empty array of objects with title and description.',
    'Quality rules:',
    'A) Reflect input fields: goal, deadline, currentLevel, weeklyHours, deliverable, learningStyle, setbacks.',
    'B) Default to 3-4 milestones; if deadline is very short, use 2-3 milestones.',
    'C) Increase difficulty gradually across milestones.',
    'D) Make every task concrete and testable, avoid vague wording.',
    'E) Each task should be brief (1 sentence) and doable in about 30-90 minutes.',
    'F) Include at least one setback-mitigation task in each milestone.',
    'G) Keep descriptions concise and action-focused.',
    'The output JSON must strictly follow this schema:',
    '{',
    '  "goal": "string",',
    '  "milestones": [',
    '    {',
    '      "title": "string",',
    '      "description": "string",',
    '      "tasks": [',
    '        { "title": "string", "description": "string" }',
    '      ]',
    '    }',
    '  ]',
    '}'
])

def ensure_string(value):
    return value.strip() if isinstance(value, str) else ''

def extract_text_from_response(payload):
    content = payload.get('content')
    if isinstance(content, list) and content:
        texts = []
        for item in content:
            if isinstance(item, dict):
                text_value = ensure_string(item.get('text'))
                if text_value:
                    texts.append(text_value)
        if texts:
            return ''.join(texts).strip()

    output = payload.get('output') if isinstance(payload.get('output'), dict) else {}
    message = output.get('message') if isinstance(output.get('message'), dict) else {}
    output_content = message.get('content') if isinstance(message.get('content'), list) else []
    if output_content:
        texts = []
        for item in output_content:
            if isinstance(item, dict):
                text_value = ensure_string(item.get('text'))
                if text_value:
                    texts.append(text_value)
        if texts:
            return ''.join(texts).strip()

    return ''

def extract_json_object(text):
    cleaned = ensure_string(text)
    if not cleaned:
        raise ValueError('Model output is empty.')

    cleaned = '\n'.join([line for line in cleaned.splitlines() if not ensure_string(line).startswith('```')]).strip()

    start = cleaned.find('{')
    if start < 0:
        raise ValueError('No JSON object found in model output.')

    depth = 0
    in_string = False
    escape = False

    for index in range(start, len(cleaned)):
        ch = cleaned[index]

        if in_string:
            if escape:
                escape = False
            elif ch == '\\':
                escape = True
            elif ch == '"':
                in_string = False
            continue

        if ch == '"':
            in_string = True
        elif ch == '{':
            depth += 1
        elif ch == '}':
            depth -= 1
            if depth == 0:
                return cleaned[start:index+1]

    raise ValueError('No complete JSON object found in model output.')

def parse_json_payload(text):
    cleaned = ensure_string(text)
    if not cleaned:
        raise ValueError('Model output is empty.')

    try:
        direct = json.loads(cleaned)
        if isinstance(direct, dict):
            return direct
    except Exception:
        pass

    raw_json = extract_json_object(cleaned)
    parsed = json.loads(raw_json)
    if not isinstance(parsed, dict):
        raise ValueError('JSON root must be an object.')
    return parsed

def normalize_response(payload):
    goal = ensure_string(payload.get('goal'))
    milestones = payload.get('milestones') if isinstance(payload.get('milestones'), list) else []

    normalized_milestones = []
    for m in milestones:
        if not isinstance(m, dict):
            continue

        title = ensure_string(m.get('title'))
        description = ensure_string(m.get('description'))
        raw_tasks = m.get('tasks') if isinstance(m.get('tasks'), list) else []

        tasks = []
        for t in raw_tasks:
            if not isinstance(t, dict):
                continue
            task_title = ensure_string(t.get('title'))
            task_desc = ensure_string(t.get('description'))
            if task_title and task_desc:
                tasks.append({'title': task_title, 'description': task_desc})

        if title and description and tasks:
            normalized_milestones.append({
                'title': title,
                'description': description,
                'tasks': tasks
            })

    if not goal or not normalized_milestones:
        raise ValueError('Invalid AI response shape.')

    return {'goal': goal, 'milestones': normalized_milestones}

def fallback_roadmap(input_payload):
    goal = ensure_string(input_payload.get('goal')) or 'Goal roadmap'
    return {
        'goal': goal,
        'milestones': [
            {
                'title': 'Current assessment',
                'description': 'Organize what is needed to achieve the goal.',
                'tasks': [
                    {'title': 'Clarify target', 'description': 'Define timeline and completion criteria in one sentence.'},
                    {'title': 'List current state', 'description': 'Write three strengths and three blockers.'}
                ]
            },
            {
                'title': 'Execution plan',
                'description': 'Define weekly actions and review cadence.',
                'tasks': [
                    {'title': 'Create weekly tasks', 'description': 'Set actionable tasks for each week.'},
                    {'title': 'Set review slot', 'description': 'Reserve 15 minutes each weekend for progress review.'}
                ]
            }
        ]
    }

def handler(event, context):
    args = event.get('arguments') if isinstance(event, dict) else {}
    input_payload = args.get('input') if isinstance(args, dict) else {}

    try:
        prompt = '\n'.join([
            SYSTEM_PROMPT,
            '',
            'User input:',
            json.dumps(input_payload, ensure_ascii=False, indent=2)
        ])

        request_body = {
            'anthropic_version': 'bedrock-2023-05-31',
            'max_tokens': 2500,
            'messages': [
                {
                    'role': 'user',
                    'content': prompt
                }
            ]
        }

        result = bedrock.invoke_model(
            modelId=os.environ.get('MODEL_ID'),
            contentType='application/json',
            accept='application/json',
            body=json.dumps(request_body)
        )

        body_text = result['body'].read().decode('utf-8')
        parsed = json.loads(body_text)
        model_text = extract_text_from_response(parsed)

        try:
            ai_payload = parse_json_payload(model_text)
        except Exception:
            repair_prompt = '\n'.join([
                'Convert the following text into exactly one valid JSON object matching the required schema.',
                'Return JSON only. No markdown, no explanation, no trailing text.',
                'If any field is missing, infer a concise safe value.',
                '',
                'Text to repair:',
                model_text
            ])

            repair_body = {
                'anthropic_version': 'bedrock-2023-05-31',
                'max_tokens': 2500,
                'messages': [
                    {
                        'role': 'user',
                        'content': repair_prompt
                    }
                ]
            }

            repair_result = bedrock.invoke_model(
                modelId=os.environ.get('MODEL_ID'),
                contentType='application/json',
                accept='application/json',
                body=json.dumps(repair_body)
            )

            repair_text = repair_result['body'].read().decode('utf-8')
            repair_parsed = json.loads(repair_text)
            repaired_model_text = extract_text_from_response(repair_parsed)

            ai_payload = parse_json_payload(repaired_model_text)

        return normalize_response(ai_payload)
    except Exception as error:
        print('[generateRoadmapWithAI] failed:', str(error))
        return fallback_roadmap(input_payload)
